cat > /tmp/extract_blocks.awk << 'EOF'
/^[0-9]+\/108$/ {
    if (page > 0) {
        printf "\nPage %d: %s\n", page, blocks[page]
    }
    page = $1
    gsub(/\/108$/, "", page)
    blocks[page] = ""
    next
}

/^[0-9]{2}_[A-Z]/ && !/\[\]$/ {
    if (blocks[page] == "") {
        blocks[page] = $1
    } else {
        blocks[page] = blocks[page] " | " $1
    }
}

END {
    if (page > 0) {
        printf "\nPage %d: %s\n", page, blocks[page]
    }
}
EOF
awk -f /tmp/extract_blocks.awk "C:/Users/Administrator/Desktop/Ladder_RAW_extracted.txt" | head -100
